class Solution {
public:
    int optimalBST(vector<string>& keys, vector<int>& freq) {
        int n = keys.size();
        vector<vector<int>> dp(n, vector<int>(n, 0));

        for (int i = 0; i < n; i++) {
            dp[i][i] = freq[i];
        }

        for (int length = 2; length <= n; length++) {
            for (int i = 0; i <= n - length; i++) {
                int j = i + length - 1;
                dp[i][j] = INT_MAX;
                int sumFreq = 0;
                for (int k = i; k <= j; k++) {
                    sumFreq += freq[k];
                }

                for (int k = i; k <= j; k++) {
                    int cost = (k > i ? dp[i][k - 1] : 0) + (k < j ? dp[k + 1][j] : 0) + sumFreq;
                    dp[i][j] = min(dp[i][j], cost);
                }
            }
        }

        return dp[0][n - 1];
    }
};

